import{_ as s,o,c as a,V as e}from"./chunks/framework.d3b95951.js";const D=JSON.parse('{"title":"工作区 Workspace","description":"","frontmatter":{},"headers":[],"relativePath":"reference/advanced/workspaces.md","filePath":"reference/advanced/workspaces.md","lastUpdated":1693551551000}'),n={name:"reference/advanced/workspaces.md"},t=e(`<h1 id="工作区-workspace" tabindex="-1">工作区 Workspace <a class="header-anchor" href="#工作区-workspace" aria-label="Permalink to &quot;工作区 Workspace&quot;">​</a></h1><p>关于如何在工作空间环境中使用 Volta 的详细信息，其中在单个 repo 中有多个项目，并且它们都希望共享 Volta 设置。</p><div class="warning custom-block"><p class="custom-block-title">警告</p><p>此功能是在 Volta 0.8.2 中添加的，在以前的版本中不起作用。</p></div><h2 id="extending-the-configuration" tabindex="-1">Extending the Configuration <a class="header-anchor" href="#extending-the-configuration" aria-label="Permalink to &quot;Extending the Configuration&quot;">​</a></h2><p>Within the <code>&quot;volta&quot;</code> section in <code>package.json</code>, you can specify an entry with key <code>&quot;extends&quot;</code>. The value of that entry should be a path to another JSON file which also has a <code>&quot;volta&quot;</code> section. Relative paths will be resolved relative to the file in which they are set. Any Volta settings (e.g. <code>&quot;node&quot;</code> or <code>&quot;yarn&quot;</code> versions) will be merged with those from the file pointed to by <code>&quot;extends&quot;</code>, with precedence given to the current file. So if you want to have a single Node version for all your projects, you would set those versions at the root, and then each project would need <em>only</em> <code>&quot;extends&quot;: &quot;../path/to/root/package.json&quot;</code>.</p><h3 id="examples" tabindex="-1">示例 <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;示例{#examples}&quot;">​</a></h3><p>Given the following folder structure and <code>package.json</code> contents:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#82AAFF;">.</span></span>
<span class="line"><span style="color:#FFCB6B;">├──</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">package.json</span></span>
<span class="line"><span style="color:#FFCB6B;">└──</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">packages</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#FFCB6B;">├──</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">cli</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#FFCB6B;">│  </span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">└──</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">package.json</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#FFCB6B;">└──</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">utils</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#FFCB6B;">└──</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">package.json</span></span></code></pre></div><ul><li><p><code>package.json</code></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">volta</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&quot;</span><span style="color:#FFCB6B;">node</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">12.16.1</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&quot;</span><span style="color:#FFCB6B;">yarn</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">1.22.4</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div></li><li><p><code>packages/cli/package.json</code></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">volta</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&quot;</span><span style="color:#FFCB6B;">extends</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">../../package.json</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div></li><li><p><code>packages/utils/package.json</code></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">volta</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&quot;</span><span style="color:#FFCB6B;">extends</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">../../package.json</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div></li></ul><p>Running <code>node</code> anywhere in the workspace would cause you to use Node <code>12.16.1</code>. And if you update that version in the root <code>package.json</code>, it will automatically be used in all of the projects, without having to duplicate the settings in each subproject.</p><h2 id="pinning-tools" tabindex="-1">Pinning Tools <a class="header-anchor" href="#pinning-tools" aria-label="Permalink to &quot;Pinning Tools&quot;">​</a></h2><p>When you run <code>volta pin</code> to select a version of a tool within a workspace, Volta will always add those settings to the <em>closest</em> <code>package.json</code> that it finds. So, in the above example, if you ran <code>volta pin node@14</code> within the <code>packages/utils</code> subproject, the new version of Node will be written into <code>packages/utils/package.json</code> and will <em>only</em> apply to the <code>utils</code> subproject, not to any of the others. This allows you to easily customize the tool versions on a per-project basis.</p><p>If you wish to use <code>volta pin</code> to make a change to the root configuration, first <code>cd</code> into the workspace root and then run <code>volta pin</code> from there.</p><h2 id="hooks" tabindex="-1">Hooks <a class="header-anchor" href="#hooks" aria-label="Permalink to &quot;Hooks&quot;">​</a></h2><p>If your project uses <a href="/advanced/hooks.html">project hooks</a>, you can place them either in a <code>.volta</code> directory in a subproject <em>or</em> in a <code>.volta</code> directory in the root. Volta will look for hooks in each location pointed to by an <code>&quot;extends&quot;</code> key, so that the settings can be customized at whatever level is needed.</p><h2 id="project-local-binaries" tabindex="-1">Project-local Binaries <a class="header-anchor" href="#project-local-binaries" aria-label="Permalink to &quot;Project-local Binaries&quot;">​</a></h2><p>In addition to looking for hooks at each level, Volta will also look at each level to detect project-local dependencies to use when running a 3rd-party tool. It will attempt to find it in <code>node_modules/.bin</code> relative to each file referenced by <code>&quot;extends&quot;</code>.</p>`,17),l=[t];function p(c,r,i,d,y,h){return o(),a("div",null,l)}const F=s(n,[["render",p]]);export{D as __pageData,F as default};
